const payload = $json.body ?? $json;
const inputList = Array.isArray(payload.workflows)
  ? payload.workflows
  : payload.workflow
    ? [payload.workflow]
    : [];

if (!inputList.length) {
  throw new Error('Send one or more workflows in body.workflows or body.workflow.');
}

const workflows = inputList.map((entry, index) => {
  if (typeof entry === 'string') {
    try {
      return JSON.parse(entry);
    } catch (error) {
      throw new Error(`Workflow ${index + 1} is not valid JSON.`);
    }
  }
  if (entry && typeof entry === 'object') return entry;
  throw new Error(`Workflow ${index + 1} must be an object or a JSON string.`);
});

return [{
  json: {
    workflows,
    meta: {
      language: String(payload.language ?? 'it').trim() || 'it',
      audience: String(payload.audience ?? 'stakeholders').trim() || 'stakeholders',
      project_title: String(payload.project_title ?? 'Livello Print - Analisi Workflow').trim(),
      subtitle: String(payload.subtitle ?? 'Presentazione automatica dei processi e delle automazioni').trim(),
      created_at: new Date().toISOString(),
    },
    config: {
      openai_api_key: 'REPLACE_OPENAI_API_KEY',
      openai_model: 'REPLACE_OPENAI_MODEL',
      google_slides_bearer_token: 'REPLACE_GOOGLE_SLIDES_BEARER_TOKEN',
      max_workflows: 10,
      max_slides: 14,
    },
  },
}];

const source = $json;
const workflows = source.workflows.slice(0, source.config.max_workflows || 10);

const toService = (type = '') => {
  const value = String(type).toLowerCase();
  if (value.includes('openai')) return 'OpenAI';
  if (value.includes('googlesheets')) return 'Google Sheets';
  if (value.includes('googledrive')) return 'Google Drive';
  if (value.includes('googleslides')) return 'Google Slides';
  if (value.includes('github')) return 'GitHub';
  if (value.includes('webhook')) return 'Webhook';
  if (value.includes('httprequest')) return 'HTTP Request';
  if (value.includes('tavily')) return 'Tavily';
  if (value.includes('email')) return 'Email';
  if (value.includes('code')) return 'Code';
  if (value.includes('set')) return 'Set';
  if (value.includes('manualtrigger')) return 'Manual Trigger';
  if (value.includes('agent')) return 'AI Agent';
  return type.split('.').pop() || type;
};

const summarizeWorkflow = (workflow, index) => {
  const nodes = Array.isArray(workflow.nodes) ? workflow.nodes : [];
  const connections = workflow.connections && typeof workflow.connections === 'object' ? workflow.connections : {};
  const nodeByName = new Map(nodes.map((node) => [node.name, node]));
  const incoming = new Map(nodes.map((node) => [node.name, 0]));
  const outgoingMain = new Map(nodes.map((node) => [node.name, []]));

  for (const [sourceName, sourceConnections] of Object.entries(connections)) {
    for (const [channelName, channelGroups] of Object.entries(sourceConnections || {})) {
      for (const group of channelGroups || []) {
        for (const link of group || []) {
          incoming.set(link.node, (incoming.get(link.node) || 0) + 1);
          if (channelName === 'main') {
            outgoingMain.get(sourceName)?.push(link.node);
          }
        }
      }
    }
  }

  const roots = nodes
    .filter((node) => (incoming.get(node.name) || 0) === 0)
    .sort((a, b) => (a.position?.[0] ?? 0) - (b.position?.[0] ?? 0) || (a.position?.[1] ?? 0) - (b.position?.[1] ?? 0))
    .map((node) => node.name);

  const orderedNodes = [...nodes]
    .sort((a, b) => (a.position?.[0] ?? 0) - (b.position?.[0] ?? 0) || (a.position?.[1] ?? 0) - (b.position?.[1] ?? 0))
    .map((node) => ({
      name: node.name,
      type: node.type,
      disabled: node.disabled === true,
    }));

  const tracePath = (startName) => {
    const visited = new Set();
    const path = [];
    let current = startName;
    while (current && !visited.has(current) && path.length < 8) {
      visited.add(current);
      path.push(current);
      const candidates = outgoingMain.get(current) || [];
      if (!candidates.length) break;
      candidates.sort((left, right) => {
        const a = nodeByName.get(left);
        const b = nodeByName.get(right);
        return (a?.position?.[0] ?? 0) - (b?.position?.[0] ?? 0) || (a?.position?.[1] ?? 0) - (b?.position?.[1] ?? 0);
      });
      current = candidates[0];
    }
    return path;
  };

  const mainPaths = roots.slice(0, 3).map((root) => tracePath(root));
  const services = [...new Set(nodes.map((node) => toService(node.type)).filter(Boolean))];
  const disabledNodes = nodes.filter((node) => node.disabled === true).map((node) => node.name);
  const aiNodes = nodes.filter((node) => String(node.type).toLowerCase().includes('langchain') || String(node.type).toLowerCase().includes('openai')).map((node) => node.name);
  const terminalNodes = nodes.filter((node) => !(outgoingMain.get(node.name) || []).length).map((node) => node.name);

  return {
    workflow_index: index + 1,
    name: String(workflow.name || `Workflow ${index + 1}`),
    node_count: nodes.length,
    root_nodes: roots,
    terminal_nodes: terminalNodes.slice(0, 6),
    services,
    ai_nodes: aiNodes,
    disabled_nodes: disabledNodes,
    ordered_nodes: orderedNodes.slice(0, 18),
    main_paths: mainPaths,
  };
};

return [{
  json: {
    ...source,
    workflow_facts: workflows.map(summarizeWorkflow),
  },
}];

