      role: 'user',
      content: `Project title: ${$json.meta.project_title}\nAudience: ${$json.meta.audience}\nLanguage: ${$json.meta.language}\nWorkflow facts:\n${JSON.stringify($json.workflow_facts, null, 2)}`
