const source = $('Extract Workflow Facts').first().json;
const content = $json.choices?.[0]?.message?.content ?? '';
let parsed;
try {
  parsed = typeof content === 'string' ? JSON.parse(content) : content;
} catch (error) {
  parsed = {};
}

const fallbackSlides = [];
fallbackSlides.push({
  kind: 'cover',
  title: source.meta.project_title,
  body: source.meta.subtitle,
});
fallbackSlides.push({
  kind: 'overview',
  title: 'Panoramica generale',
  body: `- Workflow analizzati: ${source.workflow_facts.length}\n- Obiettivo: spiegare trigger, flussi, integrazioni e output\n- Audience: ${source.meta.audience}`,
});
for (const fact of source.workflow_facts) {
  fallbackSlides.push({
    kind: 'workflow',
    title: fact.name,
    body: `- Nodi totali: ${fact.node_count}\n- Trigger: ${fact.root_nodes.join(', ') || 'non rilevato'}\n- Servizi: ${fact.services.join(', ') || 'n/d'}\n- Flusso principale: ${(fact.main_paths[0] || []).join(' -> ') || 'n/d'}\n- Output finali: ${fact.terminal_nodes.join(', ') || 'n/d'}`,
  });
}
fallbackSlides.push({
  kind: 'recommendations',
  title: 'Osservazioni finali',
  body: '- Standardizzare naming e documentazione\n- Evidenziare input, decisioni e output chiave\n- Rendere ogni workflow piu facilmente manutenibile',
});

const slides = Array.isArray(parsed.slides) && parsed.slides.length ? parsed.slides : fallbackSlides;
const clean = (value, max = 1200) => String(value ?? '').replace(/\r/g, '').trim().slice(0, max);
const limitedSlides = slides.slice(0, source.config.max_slides || 14).map((slide, index) => ({
  kind: clean(slide.kind || 'workflow', 30),
  title: clean(slide.title || `Slide ${index + 1}`, 120),
  body: clean(slide.body || '', 1400),
}));

return [{
  json: {
    presentation_title: clean(parsed.presentation_title || source.meta.project_title, 160),
    cover_subtitle: clean(parsed.cover_subtitle || source.meta.subtitle, 200),
    slides: limitedSlides,
  },
}];

const created = $json;
const plan = $('Parse Slide Plan').first().json;
const requests = [];
const existingSlides = Array.isArray(created.slides) ? created.slides.map((slide) => slide.objectId).filter(Boolean) : [];
for (const slideId of existingSlides) {
  requests.push({ deleteObject: { objectId: slideId } });
}

const slides = Array.isArray(plan.slides) ? plan.slides : [];
slides.forEach((slide, index) => {
  const slideId = `slide_${index + 1}`;
  const titleId = `title_${index + 1}`;
  const bodyId = `body_${index + 1}`;
  requests.push({
    createSlide: {
      objectId: slideId,
      insertionIndex: index,
    },
  });
  requests.push({
    createShape: {
      objectId: titleId,
      shapeType: 'TEXT_BOX',
      elementProperties: {
        pageObjectId: slideId,
        size: {
          width: { magnitude: 650, unit: 'PT' },
          height: { magnitude: 42, unit: 'PT' },
        },
        transform: {
          scaleX: 1,
          scaleY: 1,
          translateX: 35,
          translateY: 22,
          unit: 'PT',
        },
      },
    },
  });
  requests.push({ insertText: { objectId: titleId, insertionIndex: 0, text: slide.title || `Slide ${index + 1}` } });
  requests.push({
    createShape: {
      objectId: bodyId,
      shapeType: 'TEXT_BOX',
      elementProperties: {
        pageObjectId: slideId,
        size: {
          width: { magnitude: 650, unit: 'PT' },
          height: { magnitude: 390, unit: 'PT' },
        },
        transform: {
          scaleX: 1,
          scaleY: 1,
          translateX: 35,
          translateY: 88,
          unit: 'PT',
        },
      },
    },
  });
  requests.push({ insertText: { objectId: bodyId, insertionIndex: 0, text: slide.body || '' } });
});

return [{
  json: {
    presentationId: created.presentationId,
    presentationUrl: `https://docs.google.com/presentation/d/${created.presentationId}/edit`,
    requests,
    slides_count: slides.length,
    plan,
  },
}];

const batch = $('Build Slides Batch').first().json;
const plan = batch.plan || {};
return [{
  json: {
    ok: true,
    presentation_id: batch.presentationId,
    presentation_url: batch.presentationUrl,
    presentation_title: plan.presentation_title || batch.plan?.presentation_title || $('Parse Slide Plan').first().json.presentation_title,
    slides_created: batch.slides_count,
    slides: plan.slides || $('Parse Slide Plan').first().json.slides,
    message: 'Google Slides presentation created successfully.',
  },
}];
